import React from 'react';
import { Language } from '../types';

interface Props {
  current: Language;
  onSelect: (lang: Language) => void;
}

export const LanguageSelector: React.FC<Props> = ({ current, onSelect }) => {
  const langs: { code: Language; label: string }[] = [
    { code: 'es', label: 'Español' },
    { code: 'en', label: 'English' },
    { code: 'zh', label: '中文' },
  ];

  return (
    <div className="flex space-x-2">
      {langs.map((lang) => (
        <button
          key={lang.code}
          onClick={() => onSelect(lang.code)}
          className={`px-3 py-1 text-sm font-medium rounded-full transition-colors ${
            current === lang.code
              ? 'bg-blue-600 text-white'
              : 'bg-white text-gray-600 border border-gray-200 hover:bg-gray-50'
          }`}
        >
          {lang.label}
        </button>
      ))}
    </div>
  );
};

import React from 'react';

interface Props {
  label: string;
  selected: boolean;
  onClick: () => void;
  variant?: 'blue' | 'gray' | 'green';
}

export const OptionButton: React.FC<Props> = ({ label, selected, onClick, variant = 'blue' }) => {
  const getStyles = () => {
    if (selected) {
      switch (variant) {
        case 'blue': return 'bg-blue-600 border-blue-600 text-white';
        case 'gray': return 'bg-gray-600 border-gray-600 text-white';
        case 'green': return 'bg-green-600 border-green-600 text-white';
      }
    } else {
      switch (variant) {
        case 'blue': return 'bg-white border-blue-200 text-blue-600 hover:bg-blue-50';
        case 'gray': return 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50';
        case 'green': return 'bg-white border-green-200 text-green-600 hover:bg-green-50';
      }
    }
  };

  return (
    <button
      type="button"
      onClick={onClick}
      className={`px-4 py-2 text-sm font-medium rounded-lg border-2 transition-all duration-200 ${getStyles()}`}
    >
      {label}
    </button>
  );
};

import { GoogleGenAI } from "@google/genai";
import { SessionRecord, Language } from "../types";

export const getSessionInsights = async (session: SessionRecord, lang: Language) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analiza esta sesión de entrenamiento de tenis/deportes desde una perspectiva pedagógica.
    Entrenador: ${session.coach.name}, Nivel: ${session.coach.certification}.
    Jugadores: ${session.session.numPlayers}, Nivel: ${session.session.playerLevel}.
    Actividades: ${JSON.stringify(session.activities)}

    Por favor, proporciona:
    1. Un resumen de la carga pedagógica (variabilidad, tipo de instrucción, feedback).
    2. 3 sugerencias prácticas para mejorar la sesión en base a los principios de aprendizaje motor.
    3. Una valoración sobre si el feedback y la instrucción fueron equilibrados.

    Responde exclusivamente en el idioma: ${lang === 'es' ? 'Español' : lang === 'zh' ? 'Chino' : 'Inglés'}.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Error calling Gemini:", error);
    return "Error al obtener insights de la IA.";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Language, 
  CoachInfo, 
  SessionInfo, 
  ActivityData, 
  SessionRecord, 
  PlayerLevel, 
  Certification 
} from './types';
import { i18n } from './translations';
import { LanguageSelector } from './components/LanguageSelector';
import { OptionButton } from './components/OptionButton';
import { getSessionInsights } from './services/geminiService';
import { 
  User, 
  ClipboardList, 
  Plus, 
  Trash2, 
  Save, 
  History as HistoryIcon, 
  Cpu, 
  ChevronDown, 
  ChevronUp,
  Award,
  Calendar,
  Users
} from 'lucide-react';

const App: React.FC = () => {
  // State
  const [lang, setLang] = useState<Language>('es');
  const t = i18n[lang];

  const [coach, setCoach] = useState<CoachInfo>({
    name: '',
    age: '',
    certification: 'Play & Stay'
  });

  const [session, setSession] = useState<SessionInfo>({
    date: new Date().toISOString().split('T')[0],
    numPlayers: '',
    playerLevel: 'Iniciación'
  });

  const [activities, setActivities] = useState<ActivityData[]>([
    { id: '1', title: 'Actividad 1', practiceOrganization: [], instruction: [], feedback: [] }
  ]);

  const [history, setHistory] = useState<SessionRecord[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [aiInsights, setAiInsights] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('pedagogical_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  const saveToHistory = () => {
    const record: SessionRecord = {
      id: Math.random().toString(36).substr(2, 9),
      coach,
      session,
      activities,
      createdAt: new Date().toISOString()
    };
    const newHistory = [record, ...history];
    setHistory(newHistory);
    localStorage.setItem('pedagogical_history', JSON.stringify(newHistory));
    alert(lang === 'es' ? 'Sesión guardada!' : lang === 'zh' ? '课程已保存！' : 'Session saved!');
  };

  const addActivity = () => {
    const newId = (activities.length + 1).toString();
    setActivities([...activities, { 
      id: newId, 
      title: `${lang === 'es' ? 'Actividad' : lang === 'zh' ? '活动' : 'Activity'} ${newId}`, 
      practiceOrganization: [], 
      instruction: [], 
      feedback: [] 
    }]);
  };

  const removeActivity = (id: string) => {
    if (activities.length > 1) {
      setActivities(activities.filter(a => a.id !== id));
    }
  };

  const toggleOption = (activityId: string, category: 'practiceOrganization' | 'instruction' | 'feedback', option: string) => {
    setActivities(activities.map(act => {
      if (act.id === activityId) {
        const current = act[category];
        const updated = current.includes(option)
          ? current.filter(o => o !== option)
          : [...current, option];
        return { ...act, [category]: updated };
      }
      return act;
    }));
  };

  const handleAiAnalysis = async () => {
    setIsAiLoading(true);
    const insights = await getSessionInsights({ coach, session, activities, id: 'temp', createdAt: '' }, lang);
    setAiInsights(insights);
    setIsAiLoading(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <ClipboardList className="w-8 h-8 text-blue-600" />
            <h1 className="text-xl font-bold text-slate-800 hidden sm:block">{t.title}</h1>
          </div>
          <div className="flex items-center space-x-4">
            <LanguageSelector current={lang} onSelect={setLang} />
            <button 
              onClick={() => setShowHistory(!showHistory)}
              className="p-2 text-slate-500 hover:text-blue-600 transition-colors"
            >
              <HistoryIcon className="w-6 h-6" />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 pt-8 space-y-8">
        {showHistory ? (
          <section className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-2xl font-bold text-slate-800 flex items-center">
                <HistoryIcon className="w-6 h-6 mr-2 text-blue-600" />
                {t.history}
              </h2>
              <button 
                onClick={() => setShowHistory(false)}
                className="text-sm text-blue-600 font-semibold"
              >
                {lang === 'es' ? 'Volver' : lang === 'zh' ? '返回' : 'Back'}
              </button>
            </div>
            {history.length === 0 ? (
              <p className="text-center py-12 text-slate-400">{t.noHistory}</p>
            ) : (
              <div className="space-y-4">
                {history.map(record => (
                  <div key={record.id} className="p-4 border border-slate-100 rounded-xl hover:bg-slate-50 transition-colors">
                    <div className="flex justify-between items-start">
                      <div>
                        <p className="font-bold text-slate-800">{record.coach.name}</p>
                        <p className="text-sm text-slate-500">{record.session.date} • {record.session.playerLevel}</p>
                      </div>
                      <span className="bg-blue-50 text-blue-600 text-xs px-2 py-1 rounded font-bold">
                        {record.activities.length} {t.activitySection}
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </section>
        ) : (
          <>
            {/* Coach and Session Metadata */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Coach Card */}
              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
                <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center">
                  <User className="w-5 h-5 mr-2 text-blue-600" />
                  {t.coachSection}
                </h2>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-600 mb-1">{t.name}</label>
                    <input 
                      type="text" 
                      value={coach.name}
                      onChange={e => setCoach({...coach, name: e.target.value})}
                      className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none transition-all"
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-slate-600 mb-1">{t.age}</label>
                      <input 
                        type="number" 
                        value={coach.age}
                        onChange={e => setCoach({...coach, age: e.target.value ? Number(e.target.value) : ''})}
                        className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-slate-600 mb-1">{t.certification}</label>
                      <select 
                        value={coach.certification}
                        onChange={e => setCoach({...coach, certification: e.target.value as Certification})}
                        className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                      >
                        {t.certifications.map(c => (
                          <option key={c} value={c}>{c}</option>
                        ))}
                      </select>
                    </div>
                  </div>
                </div>
              </div>

              {/* Session Card */}
              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
                <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center">
                  <Calendar className="w-5 h-5 mr-2 text-blue-600" />
                  {t.sessionSection}
                </h2>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-600 mb-1">{t.date}</label>
                    <input 
                      type="date" 
                      value={session.date}
                      onChange={e => setSession({...session, date: e.target.value})}
                      className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-slate-600 mb-1">{t.numPlayers}</label>
                      <input 
                        type="number" 
                        value={session.numPlayers}
                        onChange={e => setSession({...session, numPlayers: e.target.value ? Number(e.target.value) : ''})}
                        className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-slate-600 mb-1">{t.playerLevel}</label>
                      <select 
                        value={session.playerLevel}
                        onChange={e => setSession({...session, playerLevel: e.target.value as PlayerLevel})}
                        className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
