                  <div className="bg-slate-50 px-6 py-3 border-b border-slate-200 flex justify-between items-center">
                    <span className="font-bold text-slate-700">#{(idx + 1)} - {activity.title}</span>
                    <button 
                      onClick={() => removeActivity(activity.id)}
                      className="text-slate-400 hover:text-red-500 transition-colors"
                      title={t.removeActivity}
                    >
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                  <div className="p-6 space-y-8">
                    {/* Practice Organization */}
                    <div>
                      <h3 className="text-sm font-bold text-blue-600 uppercase tracking-wider mb-4">{t.practiceOrg}</h3>
                      <div className="flex flex-wrap gap-2">
                        {Object.entries(t.options.practice).map(([key, label]) => (
                          <OptionButton 
                            key={key}
                            label={label}
                            selected={activity.practiceOrganization.includes(key)}
                            onClick={() => toggleOption(activity.id, 'practiceOrganization', key)}
                            variant="blue"
                          />
                        ))}
                      </div>
                    </div>

                    {/* Instruction */}
                    <div>
                      <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4">{t.instruction}</h3>
                      <div className="flex flex-wrap gap-2">
                        {Object.entries(t.options.instruction).map(([key, label]) => (
                          <OptionButton 
                            key={key}
                            label={label}
                            selected={activity.instruction.includes(key)}
                            onClick={() => toggleOption(activity.id, 'instruction', key)}
                            variant="gray"
                          />
                        ))}
                      </div>
                    </div>

                    {/* Feedback */}
                    <div>
                      <h3 className="text-sm font-bold text-green-600 uppercase tracking-wider mb-4">{t.feedback}</h3>
                      <div className="flex flex-wrap gap-2">
                        {Object.entries(t.options.feedback).map(([key, label]) => (
                          <OptionButton 
                            key={key}
                            label={label}
                            selected={activity.feedback.includes(key)}
                            onClick={() => toggleOption(activity.id, 'feedback', key)}
                            variant="green"
                          />
                        ))}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
