                  <div className="bg-white/20 p-2 rounded-lg">
                    <Cpu className="w-6 h-6" />
                  </div>
                  <div>
                    <h2 className="text-xl font-bold">{t.aiAnalysis}</h2>
                    <p className="text-blue-100 text-sm">Impulsado por Gemini Pro</p>
                  </div>
                </div>
                <button 
                  onClick={handleAiAnalysis}
                  disabled={isAiLoading}
                  className={`px-6 py-2 bg-white text-blue-700 rounded-xl font-bold shadow-lg hover:bg-blue-50 transition-all ${isAiLoading ? 'opacity-50 cursor-not-allowed' : ''}`}
                >
                  {isAiLoading ? t.loading : t.getInsights}
